bash_commands.command:
python -c "
import sys
sys.path.insert(0, '/workspace')

# Check imports exist
try:
    from django.conf import settings
    print('✓ django.conf.settings')
except ImportError as e:
    print('✗ django.conf.settings:', e)

try:
    from django.http import HttpResponseForbidden
    print('✓ django.http.HttpResponseForbidden')
except ImportError as e:
    print('✗ django.http.HttpResponseForbidden:', e)

try:
    from django.utils.deprecation import MiddlewareMixin
    print('✓ django.utils.deprecation.MiddlewareMixin')
except ImportError as e:
    print('✗ django.utils.deprecation.MiddlewareMixin:', e)

try:
    import time
    print('✓ time module')
except ImportError as e:
    print('✗ time module:', e)
" 2>&1 | head -20

